	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"
)

type Server struct {
	config        *Config
	engine        *gin.Engine
	httpServer    *http.Server
	sessionManager *SessionManager
	storeClient   StoreClient
	httpTransport *http.Transport
	jwtManager    *JWTManager
}

func NewServer(config *Config) (*Server, error) {
	if config.MaxConcurrentRequests == 0 {
		config.MaxConcurrentRequests = 1000
	}

	if config.Port == 0 {
		config.Port = 8080
	}

	gin.SetMode(gin.ReleaseMode)
	if config.Debug {
		gin.SetMode(gin.DebugMode)
	}

	engine := gin.New()
	engine.Use(gin.Logger())
	engine.Use(gin.Recovery())

	storeClient := NewStoreClient()
	jwtManager, err := NewJWTManager()
	if err != nil {
		return nil, fmt.Errorf("failed to create JWT manager: %w", err)
	}

	sessionManager := NewSessionManager(storeClient)

	srv := &Server{
		config:         config,
		engine:         engine,
		storeClient:    storeClient,
		jwtManager:     jwtManager,
		sessionManager: sessionManager,
	}

	srv.registerRoutes()

	return srv, nil
}

func (s *Server) Start() error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.httpServer = &http.Server{
		Addr:         addr,
		Handler:      s.createHandler(),
		ReadTimeout:  30 * time.Second,
		IdleTimeout:  90 * time.Second,
		WriteTimeout: 30 * time.Second,
	}

	if s.config.EnableTLS {
		cert, err := tls.LoadX509KeyPair(s.config.TLSCert, s.config.TLSKey)
		if err != nil {
			return fmt.Errorf("failed to load TLS certificates: %w", err)
		}
		s.httpServer.TLSConfig = &tls.Config{
			Certificates: []tls.Certificate{cert},
			NextProtos:   []string{"h2", "http/1.1"},
		}
	}

	go func() {
		klog.Infof("Starting router server on %s", addr)
		if s.config.EnableTLS {
			if err := s.httpServer.ListenAndServeTLS("", ""); err != nil && err != http.ErrServerClosed {
				klog.Fatalf("Server error: %v", err)
			}
		} else {
			if err := s.httpServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
				klog.Fatalf("Server error: %v", err)
			}
		}
	}()

	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit

	klog.Info("Shutting down server...")
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	if err := s.httpServer.Shutdown(ctx); err != nil {
		klog.Errorf("Server shutdown error: %v", err)
		return err
	}

	klog.Info("Server stopped")
	return nil
}

func (s *Server) createHandler() http.Handler {
	if s.config.EnableTLS {
		return s.engine
	}
	return h2c.NewHandler(s.engine, &http2.Server{})
}

func (s *Server) registerRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	v1Group := s.engine.Group("/v1")
	v1Group.Use(concurrencyLimitMiddleware(s.config.MaxConcurrentRequests))

	agentGroup := v1Group.Group("/namespaces/:namespace/agent-runtimes/:name")
	agentGroup.Any("/invocations/*path", s.handleAgentInvoke)

	codeGroup := v1Group.Group("/namespaces/:namespace/code-interpreters/:name")
	codeGroup.Any("/invocations/*path", s.handleCodeInterpreterInvoke)
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if err := s.storeClient.Ping(); err != nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  err.Error(),
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

package router

import (
	"context"
	"fmt"
	"io"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

func (s *Server) handleAgentInvoke(c *gin.Context) {
	sessionID := c.GetHeader("x-agentcube-session-id")
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sandbox, err := s.sessionManager.GetSandboxBySession(c.Request.Context(), sessionID, namespace, name, "AgentRuntime")
	if err != nil {
		s.handleGetSandboxError(c, err)
		return
	}

	s.forwardToSandbox(c, sandbox, path)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	sessionID := c.GetHeader("x-agentcube-session-id")
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sandbox, err := s.sessionManager.GetSandboxBySession(c.Request.Context(), sessionID, namespace, name, "CodeInterpreter")
	if err != nil {
		s.handleGetSandboxError(c, err)
		return
	}

	s.forwardToSandbox(c, sandbox, path)
}

func (s *Server) handleGetSandboxError(c *gin.Context, err error) {
	if err == store.ErrNotFound {
		c.JSON(http.StatusNotFound, gin.H{
			"error":  "session not found",
			"code":   404,
			"detail": err.Error(),
		})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{
		"error":  "internal error",
		"code":   500,
		"detail": err.Error(),
	})
}

func (s *Server) forwardToSandbox(c *gin.Context, sandbox *types.SandboxInfo, path string) {
	endpoint := s.determineUpstreamURL(sandbox, path)
	if endpoint == "" {
		c.JSON(http.StatusBadGateway, gin.H{
			"error": "no endpoint available",
			"code":  502,
		})
		return
	}

	targetURL, err := url.Parse(endpoint)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error":  "invalid endpoint URL",
			"code":   500,
			"detail": err.Error(),
		})
		return
	}

	proxy := s.createReverseProxy(targetURL, sandbox.SessionID)

	proxy.ServeHTTP(c.Writer, c.Request)
}

func (s *Server) determineUpstreamURL(sandbox *types.SandboxInfo, path string) string {
	if len(sandbox.EntryPoints) == 0 {
		return ""
	}

	for _, ep := range sandbox.EntryPoints {
		if strings.HasPrefix(path, ep.Path) {
			return ep.Endpoint
		}
	}

	return sandbox.EntryPoints[0].Endpoint
}

func (s *Server) createReverseProxy(targetURL *url.URL, sessionID string) *httputil.ReverseProxy {
	proxy := httputil.NewSingleHostReverseProxy(targetURL)

	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.Host = targetURL.Host
		req.URL.Path = targetURL.Path + req.URL.Path

		s.forwardingHeaders(req)
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		if err == io.EOF {
			w.WriteHeader(http.StatusBadGateway)
			return
		}

		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()

		if ctx.Err() == context.DeadlineExceeded {
			w.WriteHeader(http.StatusGatewayTimeout)
			return
		}

		w.WriteHeader(http.StatusBadGateway)
	}

	return proxy
}

func (s *Server) forwardingHeaders(req *http.Request) {
	req.Header.Set("X-Forwarded-For", req.RemoteAddr)
	req.Header.Set("X-Forwarded-Host", req.Host)
	req.Header.Set("X-Forwarded-Proto", "http")

	if req.TLS != nil {
		req.Header.Set("X-Forwarded-Proto", "https")
	}

	token, err := s.jwtManager.GenerateToken(map[string]interface{}{})
	if err == nil {
		req.Header.Set("Authorization", "Bearer "+token)
	}
}

package router

import (
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error)
}

type manager struct {
	storeClient     store.Store
	workloadMgrAddr string
	httpClient      *http.Client
	authToken       string
}

func NewSessionManager(storeClient store.Store) SessionManager {
	mgr := &manager{
		storeClient: storeClient,
		httpClient: &http.Client{
			Timeout: 2 * time.Minute,
			Transport: &http.Transport{
				MaxIdleConns:        100,
				MaxIdleConnsPerHost: 10,
				IdleConnTimeout:     90 * time.Second,
			},
		},
	}
	mgr.loadWorkloadManagerAuthToken()
	mgr.loadWorkloadManagerAddr()
	return mgr
}

func (m *manager) loadWorkloadManagerAddr() {
	m.workloadMgrAddr = "http://workload-manager:8080"
	if addr := ""; addr != "" {
		m.workloadMgrAddr = addr
	}
}

func (m *manager) loadWorkloadManagerAuthToken() {
	m.authToken = ""
	if token, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token"); err == nil {
		m.authToken = string(token)
	}
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error) {
	if sessionID == "" {
		return m.createSandbox(ctx, namespace, name, kind)
	}

	sandbox, err := m.storeClient.GetSandboxBySessionID(sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			return nil, fmt.Errorf("session not found: %s", sessionID)
		}
		return nil, fmt.Errorf("failed to load session: %w", err)
	}

	return sandbox, nil
}

func (m *manager) createSandbox(ctx context.Context, namespace, name, kind string) (*types.SandboxInfo, error) {
	req := types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	if err := req.Validate(); err != nil {
		return nil, fmt.Errorf("invalid request: %w", err)
	}

	var resp types.CreateSandboxResponse
	var endpoint string

	if kind == "AgentRuntime" {
		endpoint = fmt.Sprintf("%s/v1/agent-runtime", m.workloadMgrAddr)
	} else if kind == "CodeInterpreter" {
		endpoint = fmt.Sprintf("%s/v1/code-interpreter", m.workloadMgrAddr)
	} else {
		return nil, fmt.Errorf("unsupported kind: %s", kind)
	}

	httpReq, err := http.NewRequestWithContext(ctx, "POST", endpoint, nil)
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	if m.authToken != "" {
		httpReq.Header.Set("Authorization", "Bearer "+m.authToken)
	}

	httpResp, err := m.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("failed to create sandbox: %w", err)
	}
	defer httpResp.Body.Close()

	if httpResp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("failed to create sandbox: status %d", httpResp.StatusCode)
	}

	if err := json.NewDecoder(httpResp.Body).Decode(&resp); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	sandbox := &types.SandboxInfo{
		SessionID:   resp.SessionID,
		SandboxID:   resp.SandboxID,
		SandboxName: resp.SandboxName,
		EntryPoints: resp.EntryPoints,
		Namespace:   namespace,
		Name:        name,
		Kind:        kind,
		CreatedAt:   time.Now(),
		Status:      "running",
	}

	return sandbox, nil
}

package store

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type redisStore struct {
	cli                 *redis.Client
	sessionPrefix       string
	expiryIndexKey      string
	lastActivityIndexKey string
}

func NewRedisStore() Store {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		addr = "localhost:6379"
	}

	password := os.Getenv("REDIS_PASSWORD")

	cli := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	return &redisStore{
		cli:                 cli,
		sessionPrefix:       "session:",
		expiryIndexKey:      "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}
}

func (s *redisStore) Ping(ctx context.Context) error {
	_, err := s.cli.Ping(ctx).Result()
	return err
}

func (s *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionPrefix + sessionID
	data, err := s.cli.Get(ctx, key).Bytes()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (s *redisStore) StoreSandbox(ctx context.Context, sessionID string, sandbox *types.SandboxInfo) error {
	key := s.sessionPrefix + sessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := s.cli.Pipeline()
	pipe.Set(ctx, key, data, 0)
	pipe.ZAdd(ctx, s.expiryIndexKey, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sessionID,
	})
	pipe.ZAdd(ctx, s.lastActivityIndexKey, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sessionID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (s *redisStore) UpdateSandbox(ctx context.Context, sessionID string, sandbox *types.SandboxInfo) error {
	key := s.sessionPrefix + sessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	result, err := s.cli.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if !result {
		return ErrNotFound
	}

	return nil
}

func (s *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	pipe := s.cli.Pipeline()
	pipe.Del(ctx, s.sessionPrefix+sessionID)
	pipe.ZRem(ctx, s.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, s.lastActivityIndexKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (s *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.expiryIndexKey, &redis.ZRangeBy{
		Min: "-inf",
		Max: fmt.Sprintf("%d", before.Unix()),
	}).Result()
	if err != nil {
		return nil, err
	}

	if len(sessionIDs) > limit {
		sessionIDs = sessionIDs[:limit]
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.lastActivityIndexKey, &redis.ZRangeBy{
		Min: "-inf",
		Max: fmt.Sprintf("%d", before.Unix()),
	}).Result()
	if err != nil {
		return nil, err
	}

	if len(sessionIDs) > limit {
		sessionIDs = sessionIDs[:limit]
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string) error {
	key := s.sessionPrefix + sessionID
	exists, err := s.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	return s.cli.ZAdd(ctx, s.lastActivityIndexKey, redis.Z{
		Score:  float64(time.Now().Unix()),
		Member: sessionID,
	}).Err()
}

func (s *redisStore) Close() error {
	return s.cli.Close()
}

func (s *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = s.sessionPrefix + id
	}

	values, err := s.cli.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	var sandboxes []*types.SandboxInfo
	for _, v := range values {
		if v == nil {
			continue
		}

		data, ok := v.(string)
		if !ok {
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

package store

import (
	"context"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

var ErrNotFound = errors.New("store: not found")

type Store interface {
	Ping(ctx context.Context) error
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error)
	StoreSandbox(ctx context.Context, sessionID string, sandbox *types.SandboxInfo) error
	UpdateSandbox(ctx context.Context, sessionID string, sandbox *types.SandboxInfo) error
	DeleteSandboxBySessionID(ctx context.Context, sessionID string) error
	ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error)
	ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error)
	UpdateSessionLastActivity(ctx context.Context, sessionID string) error
	Close() error
}

var (
	initStoreOnce sync.Once
	provider      Store
)

func Storage() Store {
	initStoreOnce.Do(func() {
		provider = initStore()
	})
	return provider
}

func initStore() Store {
	storeType := "redis"
	if t := os.Getenv("STORE_TYPE"); t != "" {
		storeType = t
	}

	switch storeType {
	case "redis":
		return NewRedisStore()
	case "valkey":
		return NewValkeyStore()
	default:
		return NewRedisStore()
	}
}

