package types

import "time"

type SandboxInfo struct {
	Kind             string           `json:"kind"`
	SandboxID        string           `json:"sandbox_id"`
	SandboxNamespace string           `json:"sandbox_namespace"`
	Name             string           `json:"name"`
	EntryPoints      []SandboxEntryPoint `json:"entry_points"`
	SessionID        string           `json:"session_id"`
	CreatedAt        time.Time        `json:"created_at"`
	ExpiresAt        *time.Time       `json:"expires_at,omitempty"`
	Status           string           `json:"status"`
}

type SandboxEntryPoint struct {
	Path     string `json:"path"`
	Protocol string `json:"protocol"`
	Endpoint string `json:"endpoint"`
}

type CreateSandboxRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

type CreateSandboxResponse struct {
	SessionID   string             `json:"session_id"`
	SandboxID   string             `json:"sandbox_id"`
	SandboxName string             `json:"sandbox_name"`
	EntryPoints []SandboxEntryPoint `json:"entry_points"`
}

func (r *CreateSandboxRequest) Validate() error {
	if r.Kind == "" {
		return fmt.Errorf("kind is required")
	}
	if r.Name == "" {
		return fmt.Errorf("name is required")
	}
	if r.Namespace == "" {
		return fmt.Errorf("namespace is required")
	}
	return nil
}

package router

import (
	"net/http"
	"sync"
)

func concurrencyLimitMiddleware(maxConcurrent int) gin.HandlerFunc {
	semaphore := make(chan struct{}, maxConcurrent)

	return func(c *gin.Context) {
		select {
		case semaphore <- struct{}{}:
			defer func() { <-semaphore }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "too many concurrent requests",
				"code":  429,
			})
			c.Abort()
		}
	}
}

package store

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"time"

	"github.com/valkey-io/valkey-go"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type valkeyStore struct {
	cli                 *valkey.Client
	sessionPrefix       string
	expiryIndexKey      string
	lastActivityIndexKey string
}

func NewValkeyStore() Store {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		addr = "localhost:6379"
	}

	password := os.Getenv("VALKEY_PASSWORD")

	cli := valkey.NewClient(&valkey.Options{
		Addr:     addr,
		Password: password,
	})

	return &valkeyStore{
		cli:                 cli,
		sessionPrefix:       "session:",
		expiryIndexKey:      "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}
}

func (s *valkeyStore) Ping(ctx context.Context) error {
	result := s.cli.B().Ping().Do(ctx)
	if result.IsValkeyNil() {
		return fmt.Errorf("ping failed")
	}
	return nil
}

func (s *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionPrefix + sessionID
	result := s.cli.B().Get().Key(key).Do(ctx)
	if result.IsValkeyNil() {
		return nil, ErrNotFound
	}

	data, err := result.ToString()
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (s *valkeyStore) StoreSandbox(ctx context.Context, sessionID string, sandbox *types.SandboxInfo) error {
	key := s.sessionPrefix + sessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	cmds := s.cli.DoMulti(
		ctx,
		s.cli.B().Set().Key(key).Value(string(data)).Build(),
		s.cli.B().Zadd().Key(s.expiryIndexKey).ScoreMember(float64(sandbox.ExpiresAt.Unix()), sessionID).Build(),
		s.cli.B().Zadd().Key(s.lastActivityIndexKey).ScoreMember(float64(time.Now().Unix()), sessionID).Build(),
	)

	for _, cmd := range cmds {
		if cmd.Error() != nil {
			return cmd.Error()
		}
	}

	return nil
}

func (s *valkeyStore) UpdateSandbox(ctx context.Context, sessionID string, sandbox *types.SandboxInfo) error {
	key := s.sessionPrefix + sessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	result := s.cli.B().Set().Key(key).Value(string(data)).Build().Do(ctx)
	if result.Error() != nil {
		return result.Error()
	}

	if result.ToString() != "OK" {
		return ErrNotFound
	}

	return nil
}

func (s *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	cmds := s.cli.DoMulti(
		ctx,
		s.cli.B().Del().Key(s.sessionPrefix + sessionID).Build(),
		s.cli.B().Zrem().Key(s.expiryIndexKey).Member(sessionID).Build(),
		s.cli.B().Zrem().Key(s.lastActivityIndexKey).Member(sessionID).Build(),
	)

	for _, cmd := range cmds {
		if cmd.Error() != nil {
			return cmd.Error()
		}
	}

	return nil
}

func (s *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.B().Zrangebyscore().Key(s.expiryIndexKey).Min("-inf").Max(fmt.Sprintf("%d", before.Unix())).Limit(0, int64(limit)).Do(ctx).ToStringSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.B().Zrangebyscore().Key(s.lastActivityIndexKey).Min("-inf").Max(fmt.Sprintf("%d", before.Unix())).Limit(0, int64(limit)).Do(ctx).ToStringSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string) error {
	key := s.sessionPrefix + sessionID
	result := s.cli.B().Exists().Key(key).Do(ctx)
	if result.Error() != nil {
		return result.Error()
	}

	if result.ToInt64() != 1 {
		return ErrNotFound
	}

	return s.cli.B().Zadd().Key(s.lastActivityIndexKey).ScoreMember(float64(time.Now().Unix()), sessionID).Build().Do(ctx).Error()
}

func (s *valkeyStore) Close() error {
	return s.cli.Close()
}

func (s *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = s.sessionPrefix + id
	}

	values := s.cli.B().Mget().Key(keys...).Do(ctx).ToStringSlice()
	if len(values) == 0 {
		return nil, nil
	}

	var sandboxes []*types.SandboxInfo
	for _, v := range values {
		if v == "" {
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(v), &sandbox); err != nil {
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

package agentd

import (
	"context"
	"fmt"
	"time"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/log"
	"sigs.k8s.io/controller-runtime/pkg/reconcile"

	sandboxv1alpha1 "agents.x-k8s.io/api/v1alpha1"
)

const (
	SessionExpirationTimeout = 15 * time.Minute
	LastActivityAnnotationKey = "agentcube.volcano.sh/last-activity"
)

type Reconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

func (r *Reconciler) Reconcile(ctx context.Context, req reconcile.Request) (reconcile.Result, error) {
	log := log.FromContext(ctx)

	sandbox := &sandboxv1alpha1.Sandbox{}
	if err := r.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if errors.IsNotFound(err) {
			return reconcile.Result{}, nil
		}
		return reconcile.Result{}, err
	}

	lastActivityStr, ok := sandbox.Annotations[LastActivityAnnotationKey]
	if !ok || lastActivityStr == "" {
		return reconcile.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		log.Error(err, "Failed to parse last activity time", "annotation", lastActivityStr)
		return reconcile.Result{RequeueAfter: 30 * time.Second}, err
	}

	expiration := lastActivity.Add(SessionExpirationTimeout)
	if time.Now().After(expiration) {
		log.Info("Deleting sandbox due to inactivity", "sandbox", req.NamespacedName)
		if err := r.Delete(ctx, sandbox); err != nil {
			return reconcile.Result{}, err
		}
		return reconcile.Result{}, nil
	}

	return reconcile.Result{RequeueAfter: time.Until(expiration)}, nil
}

func (r *Reconciler) SetupWithManager(mgr manager.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&sandboxv1alpha1.Sandbox{}).
		Complete(r)
}

package main

import (
	"os"

	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/client/config"
	"sigs.k8s.io/controller-runtime/pkg/manager"
	"sigs.k8s.io/controller-runtime/pkg/manager/signals"
)

func main() {
	klog.InitFlags(nil)

	cfg, err := config.GetConfig()
	if err != nil {
		klog.Fatalf("Failed to get config: %v", err)
	}

	mgr, err := manager.New(cfg, manager.Options{
		MetricsBindAddress:     "0",
		HealthProbeBindAddress: "0",
	})
	if err != nil {
		klog.Fatalf("Failed to create manager: %v", err)
	}

	reconciler := &Reconciler{
		Client: mgr.GetClient(),
		Scheme: mgr.GetScheme(),
	}

	if err := reconciler.SetupWithManager(mgr); err != nil {
		klog.Fatalf("Failed to setup reconciler: %v", err)
	}

	ctx := signals.SetupSignalHandler()

	klog.Info("Starting agentd")
	if err := mgr.Start(ctx); err != nil {
		klog.Fatalf("Manager error: %v", err)
	}
}

package router

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

func (s *Server) handleAgentInvoke(c *gin.Context) {
	sessionID := c.GetHeader("x-agentcube-session-id")
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sandbox, err := s.sessionManager.GetSandboxBySession(context.Background(), sessionID, namespace, name, "AgentRuntime")
	if err != nil {
		s.handleGetSandboxError(c, err)
		return
	}

	s.forwardToSandbox(c, sandbox, path)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	sessionID := c.GetHeader("x-agentcube-session-id")
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sandbox, err := s.sessionManager.GetSandboxBySession(context.Background(), sessionID, namespace, name, "CodeInterpreter")
	if err != nil {
		s.handleGetSandboxError(c, err)
		return
	}

	s.forwardToSandbox(c, sandbox, path)
}

func (s *Server) handleGetSandboxError(c *gin.Context, err error) {
	if err == store.ErrNotFound {
		c.JSON(http.StatusNotFound, gin.H{
			"error":  "session not found",
			"code":   404,
			"detail": err.Error(),
		})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{
		"error":  "internal error",
		"code":   500,
		"detail": err.Error(),
	})
}

func (s *Server) forwardToSandbox(c *gin.Context, sandbox *types.SandboxInfo, path string) {
	endpoint := s.determineUpstreamURL(sandbox, path)
	if endpoint == "" {
		c.JSON(http.StatusBadGateway, gin.H{
			"error": "no endpoint available",
			"code":  502,
		})
		return
	}

	targetURL, err := url.Parse(endpoint)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error":  "invalid endpoint URL",
			"code":   500,
			"detail": err.Error(),
		})
		return
	}

	proxy := s.createReverseProxy(targetURL, sandbox.SessionID)

	proxy.ServeHTTP(c.Writer, c.Request)
}

func (s *Server) determineUpstreamURL(sandbox *types.SandboxInfo, path string) string {
	if len(sandbox.EntryPoints) == 0 {
		return ""
	}

	for _, ep := range sandbox.EntryPoints {
		if strings.HasPrefix(path, ep.Path) {
			return ep.Endpoint
		}
	}

	return sandbox.EntryPoints[0].Endpoint
}

func (s *Server) createReverseProxy(targetURL *url.URL, sessionID string) *httputil.ReverseProxy {
	proxy := httputil.NewSingleHostReverseProxy(targetURL)

	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.Host = targetURL.Host
		req.URL.Path = targetURL.Path + req.URL.Path

		s.forwardingHeaders(req)
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		if err == io.EOF {
			w.WriteHeader(http.StatusBadGateway)
			return
		}

		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()

		if ctx.Err() == context.DeadlineExceeded {
			w.WriteHeader(http.StatusGatewayTimeout)
			return
		}

		w.WriteHeader(http.StatusBadGateway)
	}

	return proxy
}

func (s *Server) forwardingHeaders(req *http.Request) {
	req.Header.Set("X-Forwarded-For", req.RemoteAddr)
	req.Header.Set("X-Forwarded-Host", req.Host)
	req.Header.Set("X-Forwarded-Proto", "http")

	if req.TLS != nil {
		req.Header.Set("X-Forwarded-Proto", "https")
	}

	token, err := s.jwtManager.GenerateToken(nil)
	if err == nil {
		req.Header.Set("Authorization", "Bearer "+token)
	}
}

package router

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"os"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error)
}

type manager struct {
	storeClient     store.Store
	workloadMgrAddr string
	httpClient      *http.Client
	authToken       string
}

func NewSessionManager(storeClient store.Store) SessionManager {
	mgr := &manager{
		storeClient: storeClient,
		httpClient: &http.Client{
			Timeout: 2 * time.Minute,
			Transport: &http.Transport{
				MaxIdleConns:        100,
				MaxIdleConnsPerHost: 10,
				IdleConnTimeout:     90 * time.Second,
			},
		},
	}
	mgr.loadWorkloadManagerAuthToken()
	mgr.loadWorkloadManagerAddr()
	return mgr
}

func (m *manager) loadWorkloadManagerAddr() {
	m.workloadMgrAddr = "http://workload-manager:8080"
	if addr := os.Getenv("WORKLOAD_MANAGER_URL"); addr != "" {
		m.workloadMgrAddr = addr
	}
}

func (m *manager) loadWorkloadManagerAuthToken() {
	m.authToken = ""
	if token, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token"); err == nil {
		m.authToken = string(token)
	}
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error) {
	if sessionID == "" {
		return m.createSandbox(ctx, namespace, name, kind)
	}

	sandbox, err := m.storeClient.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			return nil, fmt.Errorf("session not found: %s", sessionID)
		}
		return nil, fmt.Errorf("failed to load session: %w", err)
	}

	return sandbox, nil
}

func (m *manager) createSandbox(ctx context.Context, namespace, name, kind string) (*types.SandboxInfo, error) {
	req := types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	if err := req.Validate(); err != nil {
		return nil, fmt.Errorf("invalid request: %w", err)
	}

	var resp types.CreateSandboxResponse
	var endpoint string

	if kind == "AgentRuntime" {
		endpoint = fmt.Sprintf("%s/v1/agent-runtime", m.workloadMgrAddr)
	} else if kind == "CodeInterpreter" {
		endpoint = fmt.Sprintf("%s/v1/code-interpreter", m.workloadMgrAddr)
	} else {
		return nil, fmt.Errorf("unsupported kind: %s", kind)
	}

	httpReq, err := http.NewRequestWithContext(ctx, "POST", endpoint, nil)
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	if m.authToken != "" {
		httpReq.Header.Set("Authorization", "Bearer "+m.authToken)
	}

	httpResp, err := m.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("failed to create sandbox: %w", err)
	}
	defer httpResp.Body.Close()

	if httpResp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("failed to create sandbox: status %d", httpResp.StatusCode)
	}

	if err := json.NewDecoder(httpResp.Body).Decode(&resp); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	sandbox := &types.SandboxInfo{
		SessionID:   resp.SessionID,
		SandboxID:   resp.SandboxID,
		SandboxName: resp.SandboxName,
		EntryPoints: resp.EntryPoints,
		Namespace:   namespace,
		Name:        name,
		Kind:        kind,
		CreatedAt:   time.Now(),
		Status:      "running",
	}

	return sandbox, nil
}

package router

import (
	"net/http"

	"github.com/gin-gonic/gin"
)

func concurrencyLimitMiddleware(maxConcurrent int) gin.HandlerFunc {
	semaphore := make(chan struct{}, maxConcurrent)

	return func(c *gin.Context) {
		select {
		case semaphore <- struct{}{}:
			defer func() { <-semaphore }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "too many concurrent requests",
				"code":  429,
			})
			c.Abort()
		}
	}
}
